import React, { useRef } from 'react';
import type { NameCandidate } from '../types';
import { DownloadIcon } from './Icon';

declare const html2canvas: any;

interface NameCardProps {
  candidate: NameCandidate;
}

export const NameCard: React.FC<NameCardProps> = ({ candidate }) => {
  const cardRef = useRef<HTMLDivElement>(null);

  const handleDownload = async () => {
    if (!cardRef.current) return;
    try {
      const canvas = await html2canvas(cardRef.current, {
        backgroundColor: '#ffffff',
        scale: 3,
        useCORS: true,
      });
      const dataUrl = canvas.toDataURL('image/png');
      const link = document.createElement('a');
      link.href = dataUrl;
      link.download = `kanji-${candidate.kanji}.png`;
      link.click();
    } catch (error) {
      console.error('Download error:', error);
    }
  };

  return (
    <div className="group relative bg-white rounded-[32px] border border-gray-100 shadow-sm hover:shadow-[0_20px_80px_rgba(0,0,0,0.08)] transition-all duration-500 hover:-translate-y-2 overflow-hidden">
      <div ref={cardRef} className="p-10 text-center bg-white h-full flex flex-col justify-between min-h-[300px]">
        <div className="space-y-1">
          <p className="text-[13px] font-bold text-blue-600 uppercase tracking-widest">{candidate.hiragana}</p>
          <h3 className="text-7xl font-serif text-gray-900 py-6 tracking-tighter">{candidate.kanji}</h3>
        </div>
        <div className="pt-6 border-t border-gray-50">
          <p className="text-gray-500 text-sm leading-relaxed font-medium">
            {candidate.meaning}
          </p>
        </div>
      </div>

      <button
        onClick={handleDownload}
        className="absolute bottom-6 right-6 p-3 rounded-full bg-gray-50 text-gray-400 hover:bg-blue-600 hover:text-white transition-all opacity-0 group-hover:opacity-100 scale-90 group-hover:scale-100"
        title="Download Card"
      >
        <DownloadIcon className="w-5 h-5" />
      </button>
    </div>
  );
};
